import java.util.*;class Quadrant{public static void main(String[] a){Scanner s=new Scanner(System.in);int x=s.nextInt(),y=s.nextInt();if(x>0&&y>0)System.out.println("First");else if(x<0&&y>0)System.out.println("Second");else if(x<0&&y<0)System.out.println("Third");else if(x>0&&y<0)System.out.println("Fourth");else System.out.println("Axis/Origin");}}